// ─────────────────────────────────────────────────────────────
// PARSE E FILTRAGEM DO CSV
// ─────────────────────────────────────────────────────────────

const csvText = $input.first().json.data || $input.first().json.body || $input.first().json;

// ── Helpers ──────────────────────────────────────────────────
function parseCSV(text) {
  const lines = text.replace(/\r/g, '').split('\n');
  if (lines.length === 0) return { headers: [], rows: [] };
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
  const rows = lines.slice(1).filter(l => l.trim()).map(line => {
    // CSV simples (sem aspas aninhadas com vírgula)
    return line.split(',').map(c => c.trim().replace(/^"|"$/g, ''));
  });
  return { headers, rows };
}

function findCol(headers, candidates) {
  const lh = headers.map(h => h.toLowerCase().trim());
  for (const c of candidates) {
    const i = lh.indexOf(c.toLowerCase().trim());
    if (i !== -1) return i;
  }
  return null;
}

function getCell(row, idx) {
  if (idx === null || idx === undefined || idx >= row.length) return '';
  return (row[idx] || '').trim();
}

function normalizePhone(raw) {
  if (!raw) return null;
  let digits = raw.replace(/\D/g, '');
  if (digits.startsWith('55') && digits.length > 13) digits = digits.slice(2);
  if (!digits.startsWith('55')) digits = '55' + digits;
  if (digits.length !== 12 && digits.length !== 13) return null;
  const ddd = parseInt(digits.slice(2, 4), 10);
  if (ddd < 11 || ddd > 99) return null;
  return digits;
}

function contains(text, keywords) {
  const t = (text || '').toLowerCase();
  return keywords.some(k => t.includes(k));
}

function detectCategory(nome, prof, obs) {
  const txt = `${nome} ${prof} ${obs}`;
  const SAUDE = ['médic','enfermeir','dentist','farmâceut','fisioter','psicólog','nutricion','biomédic','veterinár','cirurgi','radiolog','fonoaud'];
  const ITALIA = ['bisavô','antepassado','ascendência italiana','nona','nonno'];
  const PROF = ['engenh','arquitet','contador','economista','administrador','gerente','diretor','professor','analista','coordenador'];
  if (contains(txt, SAUDE))  return 'SAUDE';
  if (contains(txt, ITALIA)) return 'ITALIA_SERVICOS';
  if (contains(txt, PROF))   return 'PERFIL_PROFISSIONAL';
  return 'GERAL';
}

function calcPriority(hasEmail, hasProf, cat) {
  let p = 3;
  if (hasEmail) p += 1;
  if (hasProf)  p += 1;
  if (cat === 'ITALIA_SERVICOS')   p += 4;
  else if (cat === 'SAUDE')        p += 2;
  else if (cat === 'PERFIL_PROFISSIONAL') p += 2;
  return p;
}

// ── Listas de filtro ─────────────────────────────────────────
const EMPRESA_KW = ['ltda','s.a.',' me ',' epp ','eireli','cnpj','construtora','imobili','incorporadora','holding','associa','instituto','fundação','sindicato','cooperativa','clínica','hospital','escola','colégio','academia','assessoria','consultoria','agência','financeira','seguradora','corretora','distribuidora','tecnologia','contabilidade'];
const JURIDICO_KW = ['oab','advogado','advocacia','jurídico','procurador','defensoria'];
const CONCORRENTE_KW = ['cidadania italiana','passaporte italiano','visto europeu','passaporto italiano'];

// ── Parse ────────────────────────────────────────────────────
const { headers, rows } = parseCSV(csvText);
const total = rows.length;

const idxNome   = findCol(headers, ['nome','name']);
const idxFone   = findCol(headers, ['telefone','whatsapp','celular','fone','phone','tel']);
const idxEmail  = findCol(headers, ['email','e-mail']);
const idxCidade = findCol(headers, ['cidade','city']);
const idxEstado = findCol(headers, ['estado','state','uf']);
const idxProf   = findCol(headers, ['profissao','profissão','cargo','ocupação','ocupacao']);
const idxObs    = findCol(headers, ['observacao','observação','obs','bio','descricao','descrição']);

const excluidos = { sem_telefone:0, fone_invalido:0, duplicado:0, empresa:0, juridico:0, concorrente:0 };
const seenPhones = new Set();
const approved = [];

for (const row of rows) {
  const nome   = getCell(row, idxNome) || 'Lead';
  const fone   = getCell(row, idxFone);
  const email  = getCell(row, idxEmail);
  const cidade = getCell(row, idxCidade);
  const estado = getCell(row, idxEstado);
  const prof   = getCell(row, idxProf);
  const obs    = getCell(row, idxObs);

  if (!fone)                     { excluidos.sem_telefone++;  continue; }
  const norm = normalizePhone(fone);
  if (!norm)                     { excluidos.fone_invalido++; continue; }
  if (seenPhones.has(norm))      { excluidos.duplicado++;     continue; }
  if (contains(nome, EMPRESA_KW) || /\bgrupo\b/i.test(nome)) { excluidos.empresa++;    continue; }
  if (contains(`${nome} ${prof} ${obs}`, JURIDICO_KW))        { excluidos.juridico++;   continue; }
  if (contains(obs, CONCORRENTE_KW))                          { excluidos.concorrente++; continue; }

  seenPhones.add(norm);
  const cat  = detectCategory(nome, prof, obs);
  const prio = calcPriority(!!email, !!prof, cat);

  approved.push({
    nome,
    telefone_original:    fone,
    telefone_normalizado: norm,
    email:                email || null,
    cidade:               cidade || null,
    estado:               estado || null,
    profissao:            prof || null,
    observacao:           obs || null,
    categoria:            cat,
    prioridade:           prio,
  });
}

console.log(`Total linhas: ${total}`);
console.log(`Aprovados: ${approved.length}`);
console.log(`Excluídos: ${JSON.stringify(excluidos)}`);

return approved.map(lead => ({ json: lead }));
